/* 사용량 수정 */
UPDATE tb_usage


        std_timestamp = #{entity.stdTimestamp},


        usg_val = #{entity.usgVal},

    mod_date = NOW(),

WHERE usg_idx = #{entity.usgIdx}

mapper.delete:
/* 사용량 삭제 */
DELETE FROM tb_usage 
 WHERE usg_idx = #{usgIdx}

mapper.select:
/* 사용량 상세조회ByUnique */
SELECT usg_idx,
       site_id,
       device_id,
       std_timestamp,
       std_date,
       usg_val,
       reg_date,
       mod_date
  FROM tb_usage
 WHERE site_id = #{siteId}
   AND device_id = #{deviceId}
   AND std_timestamp = #{stdTimestamp}

/* 사용량 전체 개수 조회 */
SELECT COUNT(*) AS CNT
  FROM tb_usage
 WHERE usg_idx = #{usgIdx}

/* 사용량 목록조회 BySiteId */
SELECT site_id,
       std_timestamp,
       std_date,
       SUM(usg_val) usg_val
  FROM tb_usage
 WHERE site_id = #{siteId}
   AND std_timestamp BETWEEN #{begin} AND #{end}
 GROUP BY site_id, std_timestamp, std_date
 ORDER BY std_timestamp
